                            className="p-1.5 text-slate-500 hover:text-slate-750 dark:hover:text-slate-200 hover:bg-white dark:hover:bg-slate-900 rounded-lg transition-all cursor-pointer"
                          >
                            <Plus className="h-3.5 w-3.5" />
                          </button>
                        </div>

                        <button
                          type="button"
                          onClick={handleWishlistToggle}
                          className={`p-2.5 rounded-xl border transition-all hover:scale-105 flex items-center justify-center cursor-pointer ${
                            isProductInWishlist
                              ? 'bg-rose-50 border-rose-200 text-rose-500 dark:bg-rose-955/20 dark:border-rose-900'
                              : 'bg-slate-50 border-slate-200 text-slate-400 dark:bg-slate-950 dark:border-slate-800 hover:text-slate-600 dark:hover:text-slate-300'
                          }`}
                          title={isProductInWishlist ? "Remove from Wishlist" : "Add to Wishlist"}
                        >
                          <Heart className={`h-4.5 w-4.5 ${isProductInWishlist ? 'fill-rose-500 text-rose-500' : ''}`} />
                        </button>
                      </div>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                      <button
                        type="button"
                        onClick={handleAddToCart}
                        className="bg-emerald-500 hover:bg-emerald-600 text-white font-extrabold py-3.5 rounded-2xl shadow-lg shadow-emerald-500/10 hover:shadow-emerald-600/20 transition-all flex items-center justify-center gap-2 text-sm sm:text-base cursor-pointer"
                      >
                        <ShoppingCart className="h-5 w-5" />
                        Add to Cart
                      </button>
                      <button
                        type="button"
                        onClick={handleBuyNow}
                        className="bg-amber-500 hover:bg-amber-600 text-white font-extrabold py-3.5 rounded-2xl shadow-lg shadow-amber-500/10 hover:shadow-amber-600/20 transition-all text-sm sm:text-base cursor-pointer"
                      >
                        Buy Now
                      </button>
                    </div>
                  </div>
                ) : (
                  <div className="text-center py-2">
                    <p className="text-slate-400 text-xs italic">Currently out of stock. Check back later!</p>
                  </div>
                )}
              </div>
            </div>
          </div>

          {/* Product Detail Tabs */}
          <div className="bg-white dark:bg-slate-900 border border-slate-150 dark:border-slate-850 rounded-3xl shadow-sm overflow-hidden">
            {/* Tab Bar */}
            <div className="flex border-b border-slate-200 dark:border-slate-800 overflow-x-auto scrollbar-none">
              {[
                { id: 'description', label: 'Description' },
                { id: 'specifications', label: 'Specifications' },
                { id: 'reviews', label: `Reviews (${product.reviews?.length || 0})` },
              ].map((tab) => (
                <button
                  key={tab.id}
                  type="button"
                  onClick={() => setActiveTab(activeTab === tab.id ? null : tab.id)}
                  className={`py-4 px-8 text-xs font-bold uppercase tracking-wider border-b-2 -mb-px transition-all cursor-pointer whitespace-nowrap flex-1 text-center ${
                    activeTab === tab.id
                      ? 'border-emerald-500 text-emerald-600 dark:text-emerald-400 bg-emerald-500/5'
                      : 'border-transparent text-slate-400 hover:text-slate-600 dark:hover:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800/50'
                  }`}
                >
                  {tab.label}
                </button>
              ))}
            </div>

            {/* Description Tab Content */}
            {activeTab === 'description' && (
              <div className="p-6 sm:p-8 animate-in fade-in duration-200">
                <div className="space-y-4">
                  <p className="text-xs sm:text-sm text-slate-650 dark:text-slate-300 leading-relaxed">
                    {language === 'hi' ? (product.description_hi || product.description) : (product.description_en || product.description)}
                  </p>
                  {getLocalizedFeatures().length > 0 && (
                    <div className="pt-4 border-t border-slate-100 dark:border-slate-850">
                      <h4 className="font-extrabold text-xs uppercase tracking-wider text-slate-455 mb-3 flex items-center gap-1.5">
                        <Sparkles className="h-4 w-4 text-emerald-500 animate-pulse" />
                        Key Features &amp; Highlights
                      </h4>
                      <ul className="grid grid-cols-1 sm:grid-cols-2 gap-3 text-xs sm:text-sm text-slate-650 dark:text-slate-350">
                        {getLocalizedFeatures().map((feat, idx) => (
                          <li key={idx} className="flex items-start gap-2 bg-slate-50 dark:bg-slate-955 p-3 rounded-xl border border-slate-100 dark:border-slate-850">
                            <CheckCircle2 className="h-4.5 w-4.5 text-emerald-500 mt-0.5 shrink-0" />
                            <span>{feat}</span>
                          </li>
                        ))}
                      </ul>
                    </div>
                  )}
                </div>
              </div>
            )}

            {/* Specifications Tab Content */}
            {activeTab === 'specifications' && (
              <div className="p-6 sm:p-8 animate-in fade-in duration-200">
                {getLocalizedSpecifications().length > 0 ? (
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                    {getLocalizedSpecifications().map((spec, idx) => (
                      <div key={idx} className="flex justify-between items-center bg-slate-50 dark:bg-slate-955 border border-slate-150 dark:border-slate-850 px-4 py-3 rounded-xl text-xs sm:text-sm">
                        <span className="font-bold text-slate-400">{spec.key}</span>
                        <span className="font-semibold text-slate-800 dark:text-slate-200">{spec.value}</span>
                      </div>
                    ))}
                  </div>
                ) : (
                  <p className="text-slate-400 text-xs italic">No technical specifications provided.</p>
                )}
              </div>
            )}

            {/* Reviews Tab Content */}
            {activeTab === 'reviews' && (
              <div className="p-6 sm:p-8 animate-in fade-in duration-200">
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                  <div className="lg:col-span-2 space-y-4">
                    <h3 className="text-xs font-bold border-b border-slate-100 dark:border-slate-800 pb-2 flex items-center gap-2 uppercase tracking-wider text-slate-400">
                      <MessageSquare className="h-4 w-4 text-emerald-500" />
                      Customer Feedback
                    </h3>
                    {(!product.reviews || product.reviews.length === 0) ? (
                      <p className="text-slate-400 text-xs italic py-2">No reviews yet. Be the first to share your experience!</p>
                    ) : (
                      <div className="divide-y divide-slate-100 dark:divide-slate-850 space-y-3">
                        {product.reviews.map((rev, index) => (
                          <div key={rev._id || index} className="pt-3 first:pt-0">
                            <div className="flex justify-between items-start">
                              <div>
                                <p className="font-semibold text-xs text-slate-800 dark:text-slate-100">{rev.user_name}</p>
                                <div className="flex text-amber-400 mt-0.5">
                                  {[...Array(5)].map((_, idx) => (
                                    <Star key={idx} className={`h-3 w-3 ${idx < rev.rating ? 'fill-current' : 'text-slate-200 dark:text-slate-700'}`} />
                                  ))}
                                </div>
                              </div>
                              <span className="text-[9px] text-slate-455 dark:text-slate-500">
                                {rev.created_at ? new Date(rev.created_at).toLocaleDateString() : 'Recently'}
                              </span>
                            </div>
                            <p className="text-xs text-slate-600 dark:text-slate-300 mt-1 pl-0.5 leading-relaxed">{rev.comment}</p>
                          </div>
                        ))}
                      </div>
                    )}
                  </div>
                  <div>
                    <div className="bg-slate-50 dark:bg-slate-955 border border-slate-150 dark:border-slate-850 p-4 rounded-2xl">
                      <h3 className="text-xs font-bold mb-3 uppercase tracking-wider text-slate-450">Write a Review</h3>
                      {user ? (
                        <form onSubmit={handleReviewSubmit} className="space-y-3">
                          {reviewMessage && (
                            <p className="text-[10px] text-emerald-550 bg-emerald-500/10 p-2 rounded-lg border border-emerald-200 dark:border-emerald-900 font-bold">{reviewMessage}</p>
                          )}
                          {reviewErr && (
                            <p className="text-[10px] text-red-500 bg-red-500/10 p-2 rounded-lg border border-red-200 dark:border-red-900">{reviewErr}</p>
                          )}
                          <div>
                            <span className="block text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1.5">Star Rating</span>
                            <div className="flex text-amber-400 gap-1">
                              {[1, 2, 3, 4, 5].map((star) => (
                                <button key={star} type="button" onClick={() => setRating(star)} className="hover:scale-110 transition-transform cursor-pointer">
                                  <Star className={`h-4.5 w-4.5 ${star <= rating ? 'fill-current' : 'text-slate-200 dark:text-slate-700'}`} />
                                </button>
                              ))}
                            </div>
                          </div>
                          <div>
                            <span className="block text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1.5">Written Review</span>
                            <textarea value={comment} onChange={(e) => setComment(e.target.value)} rows="3" placeholder="Share your experience about product quality..." className="w-full px-2.5 py-1.5 text-xs bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-lg focus:outline-none focus:ring-1 focus:ring-emerald-500 text-slate-800 dark:text-slate-100" />
                          </div>
                          <button type="submit" disabled={submittingReview} className="w-full flex items-center justify-center space-x-1.5 py-2 px-3 bg-emerald-500 hover:bg-emerald-600 text-white rounded-lg text-xs font-bold shadow-md disabled:opacity-50 transition-all cursor-pointer">
                            <Send className="h-3.5 w-3.5" />
                            <span>{submittingReview ? 'Submitting...' : 'Submit Review'}</span>
                          </button>
                        </form>
                      ) : (
                        <div className="text-center py-4">
                          <p className="text-slate-400 text-[10px] mb-3">Please log in to submit your star rating and feedback.</p>
                          <button onClick={() => navigate('/login')} className="px-4 py-1.5 bg-white hover:bg-slate-100 dark:bg-slate-900 dark:hover:bg-slate-800 text-slate-800 dark:text-slate-205 rounded-lg text-xs font-bold border border-slate-200 dark:border-slate-800 cursor-pointer">Go to Login</button>
                        </div>
                      )}
                    </div>
                  </div>
                </div>
              </div>
            )}

            {/* Empty state when no tab selected */}
            {activeTab === null && (
              <div className="px-6 py-10 text-center">
                <p className="text-slate-400 text-xs">Click a tab above to view product details.</p>
              </div>
            )}
          </div>



          {/* Section 4: Related Products */}
          <div id="related-section" className="bg-white dark:bg-slate-900 border border-slate-150 dark:border-slate-850 rounded-3xl p-6 sm:p-8 shadow-sm scroll-mt-28">
            <h2 className="text-sm font-black text-slate-400 uppercase tracking-wider mb-4 border-b border-slate-100 dark:border-slate-800 pb-2">Related Products</h2>
            {loadingRelated ? (
              <div className="flex justify-center items-center py-8">
                <div className="animate-spin rounded-full h-8 w-8 border-t-2 border-emerald-500"></div>
              </div>
            ) : (
              <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 2xl:grid-cols-6 gap-4 sm:gap-6">
                {(relatedProducts.length > 0 ? relatedProducts : [
                  { _id: 'fallback-1', name: 'Eco-Friendly Bamboo Toothbrush Pack', price: 299, discount: 10, rating: 4.5, images: ['https://images.unsplash.com/photo-1607613009820-a29f7bb81c04?w=400'], stock: 15, category: product.category, description: 'Premium eco-friendly bamboo toothbrushes.' },
                  { _id: 'fallback-2', name: 'Organic Cold Pressed Coconut Oil', price: 449, discount: 15, rating: 4.8, images: ['https://images.unsplash.com/photo-1622484211148-716d27dcbf5c?w=400'], stock: 20, category: product.category, description: '100% organic cold pressed coconut oil.' },
                  { _id: 'fallback-3', name: 'Assorted Premium Dry Fruits Box', price: 999, discount: 20, rating: 4.9, images: ['https://images.unsplash.com/photo-1596560548464-f010549b84d7?w=400'], stock: 8, category: product.category, description: 'Gourmet selection of dry fruits.' },
                  { _id: 'fallback-4', name: 'Handcrafted Ceramic Tea Cups (Set of 6)', price: 699, discount: 5, rating: 4.6, images: ['https://images.unsplash.com/photo-1514432324607-a09d9b4aefdd?w=400'], stock: 12, category: product.category, description: 'Elegant ceramic tea cups.' }
                ]).map((item) => (
                  <RelatedProductCard key={item._id} item={item} />
                ))}
              </div>
            )}
          </div>

          {/* Section 5: Recently Viewed Products */}
          {recentlyViewed.length > 0 && (
            <div id="recently-viewed-section" className="bg-white dark:bg-slate-900 border border-slate-150 dark:border-slate-850 rounded-3xl p-6 sm:p-8 shadow-sm scroll-mt-28">
              <h2 className="text-sm font-black text-slate-400 uppercase tracking-wider mb-4 border-b border-slate-100 dark:border-slate-800 pb-2">Recently Viewed Products</h2>
              <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 2xl:grid-cols-6 gap-4 sm:gap-6">
                {recentlyViewed.map((item) => (
                  <RelatedProductCard key={item._id} item={item} />
                ))}
              </div>
            </div>
          )}
          </>
        )}


      {/* Full-Screen Image Gallery Modal */}
      {isPreviewOpen && (
        <div className="fixed inset-0 bg-slate-950/90 z-50 flex items-center justify-center backdrop-blur-md">
          <button
            type="button"
            onClick={() => setIsPreviewOpen(false)}
            className="absolute top-4 right-4 p-2 bg-white/10 hover:bg-white/20 text-white rounded-full transition-colors cursor-pointer"
          >
            <ArrowLeft className="h-6 w-6 rotate-180" />
          </button>

          <div className="max-w-4xl w-full px-4 flex flex-col items-center gap-4">
            <div className="relative w-full aspect-square md:aspect-video bg-black rounded-3xl overflow-hidden flex items-center justify-center shadow-2xl">
              {/* Navigation Arrows */}
              <button
                type="button"
                onClick={() => setPreviewImageIndex(prev => (prev - 1 + imagesList.length) % imagesList.length)}
                className="absolute left-4 p-2 bg-black/50 hover:bg-black/80 text-white rounded-full transition-colors cursor-pointer z-10"
              >
                <ArrowLeft className="h-6 w-6" />
              </button>
              <img
                src={imagesList[previewImageIndex]}
                alt={`${product.name} - Full Preview ${previewImageIndex + 1}`}
                className="max-w-full max-h-full object-contain"
              />
              <button
                type="button"
                onClick={() => setPreviewImageIndex(prev => (prev + 1) % imagesList.length)}
                className="absolute right-4 p-2 bg-black/50 hover:bg-black/80 text-white rounded-full transition-colors cursor-pointer z-10"
              >
                <ArrowLeft className="h-6 w-6 rotate-180" />
              </button>
            </div>

            {/* Thumbnails list inside full screen gallery */}
            <div className="flex gap-2 overflow-x-auto py-2 w-full justify-center scrollbar-none">
              {imagesList.map((img, idx) => (
                <button
                  key={idx}
                  type="button"
                  onClick={() => setPreviewImageIndex(idx)}
                  className={`w-12 h-12 rounded-lg border overflow-hidden flex-shrink-0 transition-all ${
                    previewImageIndex === idx
                      ? 'border-emerald-500 ring-2 ring-emerald-500/50 shadow-md scale-110'
                      : 'border-slate-700 hover:border-slate-500'
                  }`}
                >
                  <img src={img} alt={`Thumb ${idx + 1}`} className="w-full h-full object-cover" />
                </button>
              ))}
            </div>
          </div>
        </div>
      )}

    </div>
  </div>
  );
};
